CREATE TRIGGER contacts_after_insert_trigger
          AFTER INSERT ON contacts
        BEGIN
          UPDATE contacts SET inserted_at = STRFTIME('%s', 'NOW') WHERE id = NEW.id AND inserted_at IS NULL;
          UPDATE contacts SET updated_at = STRFTIME('%s', 'NOW') WHERE id = NEW.id;
        END;

CREATE TRIGGER contacts_after_update_trigger
          AFTER UPDATE ON contacts
        BEGIN
          UPDATE contacts SET updated_at = STRFTIME('%s', 'NOW') WHERE id = NEW.id;
        END;

